function solve(grid, x, y, k) {
    // Extract the submatrix
    let submatrix = [];
    for (let i = 0; i < k; i++) {
        let row = [];
        for (let j = 0; j < k; j++) {
            row.push(grid[x + i][y + j]);
        }
        submatrix.push(row);
    }
    // Reverse the submatrix rows
    submatrix.reverse();
    // Put back into the grid
    for (let i = 0; i < k; i++) {
        for (let j = 0; j < k; j++) {
            grid[x + i][y + j] = submatrix[i][j];
        }
    }
    return grid;
}

