fn solve(grid: Vec<Vec<i64>>, x: i64, y: i64, k: i64) -> Vec<Vec<i64>> {
    let mut new_grid = grid.clone();
    let k = k as usize;
    let x = x as usize;
    let y = y as usize;

    let mut submatrix: Vec<Vec<i64>> = Vec::with_capacity(k);
    for i in 0..k {
        let row = new_grid[x + i].clone();
        let mut sub_row = Vec::with_capacity(k);
        for j in 0..k {
            sub_row.push(row[y + j]);
        }
        submatrix.push(sub_row);
    }

    let reversed_submatrix: Vec<Vec<i64>> = submatrix.iter().rev().cloned().collect();

    for i in 0..k {
        let start_row = x + i;
        let start_col = y;
        for j in 0..k {
            new_grid[start_row][start_col + j] = reversed_submatrix[i][j];
        }
    }

    new_grid
}
```

